#include <bits/stdc++.h>
using namespace std;

const int N=150;

int n,m,dfn[N],mp[N],sz[N],w[N],f[N][N],num;
int head[N],ver[N<<1],edge[N<<1],nxt[N<<1],tot;

void add(int u,int v,int w){
    ver[++tot]=v,edge[tot]=w,nxt[tot]=head[u],head[u]=tot;
}

void dfs(int x,int last){
    sz[x]=1;
    dfn[x]=++num;
    mp[num]=x;
    for(int i=head[x],y;i;i=nxt[i])
        if(ver[i]!=last){
            w[y=ver[i]]=edge[i];
            dfs(y,x);
            sz[x]+=sz[y];
        }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        add(u,v,w);
        add(v,u,w);
    }
    dfs(1,0);
    m++;
    memset(f,0xcf,sizeof(f));
    f[1][0]=0;
    for(int i=1;i<=n;i++){
        int x=mp[i];
        for(int j=0;j<=m;j++){
            f[i+1][j+1]=max(f[i+1][j+1],f[i][j]+w[x]);
            f[i+sz[x]][j]=max(f[i+sz[x]][j],f[i][j]);
        }
    }
    printf("%d",f[n+1][m]);
    return 0;
}
